    // Handling forall and thereexists for x
    for(int x = 0; x < 4; x++) {
        // Handling forall and thereexists for y
        for(int y = 0; y < 4; y++) {
            // Handling forall and thereexists for z
            for(int z = 0; z < 4; z++) {
                if(quants[0] && quants[1] && quants[2]) {
                    // forall x forall y forall z F(x,y,z)
                    if(!data[x][y][z]) return false;
                } else if(!quants[0] && !quants[1] && !quants[2]) {
                    // thereexists x thereexists y thereexists z F(x,y,z)
                    if(data[x][y][z]) return true;
                } else {
                    bool result = data[x][y][z];
                    if(quants[2] == 0 && result) return true; // thereexists z
                    if(quants[2] && !result) break; // forall z needs all true, breaks on false

                    if(y == 3 && quants[1] == 0 && result) return true; // thereexists y after checking all z
                    if(x == 3 && quants[0] == 0 && result) return true; // thereexists x after checking all y and z

                    if(y == 3 && quants[1] && !result) break; // forall y breaks on any false
                    if(x == 3 && quants[0] && !result) return false; // forall x returns false on any false
                }
            }
            if(quants[1] && quants[2] && !data[x][y][3]) return false; // forall y, z
        }
        if(quants[0] && quants[1] && !data[x][3][3]) return false; // forall x, y
    }

    // Determining the return value based on the combination of quantifiers
    if(quants[0] && quants[1] && quants[2]) {
        return true; // forall x forall y forall z
    } else if(!quants[0] || !quants[1] || !quants[2]) {
        return false;  // If any thereexists without being successful indicates false
    }

    return true; // Default to true if all thereexists were not successful but no forall failure detected
}

