    for (int x = 0; x < 4; ++x) {
        bool resultX = !quants[0]; // Assume thereexists for x, so start with false and look for a true.
        for (int y = 0; y < 4; ++y) {
            bool resultY = !quants[1]; // Assume thereexists for y, so start with false.
            for (int z = 0; z < 4; ++z) {
                bool resultZ = data[x][y][z]; // Directly take the value from the data for z.
                if (quants[2]) { // If 'forall' for z.
                    if (!resultZ) { // If any z fails for 'forall', y fails.
                        resultY = false;
                        break; // Exit z loop early because the 'forall' condition failed.
                    }
                    resultY = true; // If we made it through all z, set resultY to true for 'forall'.
                } else if (resultZ) { // If 'thereexists' for z and we find a true.
                    resultY = true;
                    break; // Exit z loop early because we found a satisfying z.
                }
            }
            if (quants[1] && !resultY) { // If 'forall' for y and resultY is false.
                resultX = false;
                break; // Exit y loop early because the 'forall' condition failed.
            } else if (!quants[1] && resultY) { // If 'thereexists' for y and we found a true.
                resultX = true;
                break; // Exit y loop early because we found a satisfying y.
            }
        }
        if (quants[0] && !resultX) { // If 'forall' for x and resultX is false.
            return false; // The entire formula fails if any x fails for 'forall'.
        } else if (!quants[0] && resultX) { // If 'thereexists' for x and we found a true.
            return true; // The formula is satisfied if we find a satisfying x.
        }
    }
    // If we're looking for 'forall' in all dimensions and didn't return false, it means all conditions passed.
    return quants[0];
}

int main() {
    bool data[4][4][4] = {{{true}}}; // Simplified example data where F(x,y,z) = true for simplicity.
    bool quants[3] = {1, 0, 1}; // Example quantifiers configuration, representing Forall x, ThereExists y, Forall z.

    // Execute the solver function
    bool result = quantificationalSolver(data, quants);
    std::cout << "The formula evaluates to: " << std::boolalpha << result << std::endl;

    return 0;
}
